import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    def calculate_distance(pos1, pos2):
        return np.linalg.norm(pos1 - pos2)

    best_ratio = -float('inf')
    best_node = None

    for i, customer_pos in enumerate(unvisited_customers):
        dist_to_customer = calculate_distance(cur_truck_pos, customer_pos)
        sum_dist_to_trucks = sum([calculate_distance(truck_pos, customer_pos) for truck_pos in all_truck_pos])

        ratio = sum_dist_to_trucks / dist_to_customer

        if ratio > best_ratio:
            best_ratio = ratio
            best_node = i

    return best_node
